382→/// Validate and normalize a JSON Schema document into the OpenAI-compatible
383→/// function-calling subset via `json_schema_ast` canonicalization plus
384→/// recursive `schemars` transforms.
385→pub(crate) fn sanitize_schema_for_openai_compat(schema: &mut serde_json::Value) {
386→    let canonical = canonicalize_schema_for_openai_compat(schema);
387→
388→    let Ok(mut transformed) = Schema::try_from(canonical.clone()) else {
389→        *schema = canonical;
390→        return;
391→    };
392→    let mut replace_const = ReplaceConstValue::default();
393→    replace_const.transform(&mut transformed);
394→    let mut replace_unevaluated_properties = ReplaceUnevaluatedProperties::default();
395→    replace_unevaluated_properties.transform(&mut transformed);
396→    let mut replace_prefix_items = ReplacePrefixItems::default();
397→    replace_prefix_items.transform(&mut transformed);
398→    let mut remove_ref_siblings = RemoveRefSiblings::default();
399→    remove_ref_siblings.transform(&mut transformed);
400→    let mut subset_transform = RecursiveTransform(OpenAiSchemaSubsetTransform);
401→    subset_transform.transform(&mut transformed);
402→
403→    // Strip empty `{}` schemas from anyOf/oneOf (left behind by
404→    // canonicalization of `not` and other negation keywords) and collapse
405→    // single-variant composites inline (issue #743).
406→    let mut simplify_composite = RecursiveTransform(SimplifyCompositeTransform);
407→    simplify_composite.transform(&mut transformed);
408→
409→    // Infer `"type": "string"` for required properties that have metadata
410→    // (e.g. `description`) but no type-defining keyword. Must run before
411→    // pruning so the property is considered "defined" (#793).
412→    let mut ensure_type = RecursiveTransform(EnsurePropertyTypeTransform);
413→    ensure_type.transform(&mut transformed);
414→
415→    // Prune `required` entries that reference properties not defined in
416→    // `properties`. Keyword stripping above can remove property definitions
