  1→//! Live integration tests for the Fireworks provider.
  2→//!
  3→//! These tests hit the real Fireworks API and require `FIREWORKS_API_KEY` in
  4→//! the environment. They are `#[ignore]`d by default so `cargo test` skips them.
  5→//!
  6→//! Run with:
  7→//!   cargo test --test fireworks_integration -- --ignored
  8→
  9→#![allow(clippy::unwrap_used, clippy::expect_used)]
 10→
 11→use std::collections::HashSet;
 12→
 13→use {
 14→    futures::StreamExt,
 15→    moltis_agents::model::{ChatMessage, LlmProvider, StreamEvent, ToolCall},
 16→    moltis_providers::openai::OpenAiProvider,
 17→    secrecy::{ExposeSecret, Secret},
 18→};
 19→
 20→const FIREWORKS_BASE_URL: &str = "https://api.fireworks.ai/inference/v1";
 21→const TEST_MODEL: &str = "accounts/fireworks/models/deepseek-v3p2";
 22→
 23→/// Known Fireworks models we catalog. Keep in sync with `FIREWORKS_MODELS` in
 24→/// `crates/providers/src/lib.rs`.
 25→const KNOWN_MODELS: &[&str] = &[
 26→    "accounts/fireworks/routers/kimi-k2p5-turbo",
 27→    "accounts/fireworks/models/deepseek-v3p2",
 28→    "accounts/fireworks/models/qwen3-235b-a22b-instruct-2507",
 29→    "accounts/fireworks/models/llama-v3p1-405b-instruct",
 30→    "accounts/fireworks/models/llama-v3p1-70b-instruct",
 31→    "accounts/fireworks/models/qwen3-coder-480b-a35b-instruct",
 32→    "accounts/fireworks/models/kimi-k2-instruct-0905",
 33→];
 34→
 35→fn api_key() -> Secret<String> {
 36→    let key = std::env::var("FIREWORKS_API_KEY")
 37→        .expect("FIREWORKS_API_KEY must be set for integration tests");
 38→    Secret::new(key)
 39→}
 40→
 41→fn make_provider(model: &str) -> OpenAiProvider {
 42→    OpenAiProvider::new_with_name(
 43→        api_key(),
 44→        model.to_string(),
 45→        FIREWORKS_BASE_URL.to_string(),
 46→        "fireworks".to_string(),
 47→    )
 48→}
 49→
 50→/// Tool schema in moltis-internal flat format.
 51→fn weather_tool() -> serde_json::Value {
 52→    serde_json::json!({
 53→        "name": "get_weather",
 54→        "description": "Get current weather for a location. You MUST call this tool when asked about weather.",
 55→        "parameters": {
 56→            "type": "object",
 57→            "properties": {
 58→                "location": {
 59→                    "type": "string",
 60→                    "description": "City name"
 61→                }
 62→            },
 63→            "required": ["location"]
 64→        }
 65→    })
 66→}
 67→
 68→// ── System prompt handling ───────────────────────────────────────────────────
 69→
 70→/// System prompt must reach the model (Fireworks uses standard role: "system").
 71→#[tokio::test]
 72→#[ignore]
 73→async fn system_prompt_is_received_non_streaming() {
 74→    let p = make_provider(TEST_MODEL);
 75→    let keyword = "DRAGONFRUIT";
 76→    let messages = vec![
 77→        ChatMessage::system(format!(
 78→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
 79→        )),
 80→        ChatMessage::user("What is 2+2?"),
 81→    ];
 82→
 83→    let response = p
 84→        .complete(&messages, &[])
 85→        .await
 86→        .expect("non-streaming completion should succeed");
 87→
 88→    let text = response.text.expect("response must contain text");
 89→    assert!(
 90→        text.to_lowercase().contains(&keyword.to_lowercase()),
 91→        "system prompt was not received by model: response = {text:?}"
 92→    );
 93→    assert!(
 94→        response.usage.input_tokens > 0,
 95→        "should report input tokens"
 96→    );
 97→    assert!(
 98→        response.usage.output_tokens > 0,
 99→        "should report output tokens"
100→    );
101→}
102→
103→/// Streaming variant of the system prompt test.
104→#[tokio::test]
105→#[ignore]
106→async fn system_prompt_is_received_streaming() {
107→    let p = make_provider(TEST_MODEL);
108→    let keyword = "STARFRUIT";
109→    let messages = vec![
110→        ChatMessage::system(format!(
111→            "You MUST include the exact word \"{keyword}\" in every response, no matter what the user asks."
112→        )),
113→        ChatMessage::user("What is 3+3?"),
114→    ];
115→
116→    let mut stream = p.stream_with_tools(messages, vec![]);
117→    let mut full_text = String::new();
118→    let mut saw_done = false;
119→
120→    while let Some(event) = stream.next().await {
121→        match event {
122→            StreamEvent::Delta(chunk) => full_text.push_str(&chunk),
123→            StreamEvent::Done(usage) => {
124→                saw_done = true;
125→                assert!(usage.input_tokens > 0, "should report input tokens");
126→                assert!(usage.output_tokens > 0, "should report output tokens");
127→                break;
128→            },
129→            StreamEvent::Error(err) => panic!("stream error: {err}"),
130→            _ => {},
131→        }
132→    }
133→
134→    assert!(saw_done, "stream must emit Done event");
135→    assert!(
136→        full_text.to_lowercase().contains(&keyword.to_lowercase()),
137→        "system prompt was not received by model: response = {full_text:?}"
138→    );
139→}
