141→// ── Tool calling ─────────────────────────────────────────────────────────────
142→
143→/// Model must be able to call a tool via non-streaming completion.
144→#[tokio::test]
145→#[ignore]
146→async fn tool_call_round_trip_non_streaming() {
147→    let p = make_provider(TEST_MODEL);
148→    let tools = vec![weather_tool()];
149→
150→    let messages = vec![ChatMessage::user(
151→        "What's the weather like in Tokyo? You must use the get_weather tool to answer.",
152→    )];
153→
154→    let response = p
155→        .complete(&messages, &tools)
156→        .await
157→        .expect("completion with tools should succeed");
158→
159→    assert!(
160→        !response.tool_calls.is_empty(),
161→        "model should call the get_weather tool, got text: {:?}",
162→        response.text
163→    );
164→
165→    let tool_call = &response.tool_calls[0];
166→    assert_eq!(tool_call.name, "get_weather");
167→    let args = &tool_call.arguments;
168→    assert!(
169→        args.get("location").is_some(),
170→        "tool call should include location, got: {args}"
171→    );
172→}
173→
174→/// Streaming variant: model calls a tool with proper streaming events.
175→#[tokio::test]
176→#[ignore]
177→async fn tool_call_round_trip_streaming() {
178→    let p = make_provider(TEST_MODEL);
179→    let tools = vec![weather_tool()];
180→
181→    let messages = vec![ChatMessage::user(
182→        "What's the weather in Paris? You must use the get_weather tool.",
183→    )];
184→
185→    let mut stream = p.stream_with_tools(messages, tools);
186→    let mut saw_tool_start = false;
187→    let mut saw_done = false;
188→    let mut tool_name = String::new();
189→
190→    while let Some(event) = stream.next().await {
191→        match event {
192→            StreamEvent::ToolCallStart { name, .. } => {
193→                saw_tool_start = true;
194→                tool_name = name;
195→            },
196→            StreamEvent::Done(_) => {
197→                saw_done = true;
198→                break;
199→            },
200→            StreamEvent::Error(err) => panic!("stream error: {err}"),
201→            _ => {},
202→        }
203→    }
204→
205→    assert!(saw_done, "stream must emit Done event");
206→    assert!(saw_tool_start, "stream should include a tool call");
207→    assert_eq!(tool_name, "get_weather");
208→}
209→
210→/// Multi-turn tool use: model calls tool, receives result, responds.
211→#[tokio::test]
212→#[ignore]
213→async fn multi_turn_tool_use() {
214→    let p = make_provider(TEST_MODEL);
215→    let tools = vec![weather_tool()];
216→
217→    // Step 1: model should call the tool
218→    let messages = vec![ChatMessage::user(
219→        "What's the weather in London? You must use the get_weather tool.",
220→    )];
221→    let response = p
222→        .complete(&messages, &tools)
223→        .await
224→        .expect("first turn should succeed");
225→
226→    assert!(
227→        !response.tool_calls.is_empty(),
228→        "should call get_weather, got text: {:?}",
229→        response.text
230→    );
231→    let tc = &response.tool_calls[0];
232→
233→    // Step 2: provide tool result, model should produce a text response
234→    let messages = vec![
235→        ChatMessage::user("What's the weather in London? You must use the get_weather tool."),
236→        ChatMessage::assistant_with_tools(response.text.clone(), vec![ToolCall {
237→            id: tc.id.clone(),
238→            name: tc.name.clone(),
239→            arguments: tc.arguments.clone(),
240→            metadata: tc.metadata.clone(),
241→        }]),
242→        ChatMessage::tool(&tc.id, r#"{"temperature": 15, "condition": "cloudy"}"#),
243→    ];
244→
245→    let final_response = p
246→        .complete(&messages, &tools)
247→        .await
248→        .expect("second turn should succeed");
249→
250→    let text = final_response.text.expect("should have text response");
