  2→
  3→/// Make a JSON Schema node nullable by adding `"null"` to its type.
  4→///
  5→/// For schemas using `"type": "string"` (or any single type), this converts to
  6→/// `"type": ["string", "null"]`. For schemas using `anyOf`/`oneOf`, it appends
  7→/// a `{"type": "null"}` variant. Already-nullable schemas are left unchanged.
  8→///
  9→/// For enum-only schemas (no `type` key — common after canonicalization strips
 10→/// redundant type annotations), `null` is appended directly to the enum array
 11→/// so the model can omit the field (issue #712).
 12→fn make_nullable(schema: &mut serde_json::Value) {
 13→    let Some(obj) = schema.as_object_mut() else {
 14→        return;
 15→    };
 16→
 17→    if let Some(ty) = obj.get("type") {
 18→        if ty.as_str() == Some("null") {
 19→            return;
 20→        }
 21→        if let Some(arr) = ty.as_array()
 22→            && arr.iter().any(|value| value.as_str() == Some("null"))
 23→        {
 24→            return;
 25→        }
 26→    }
 27→
 28→    if let Some(ty) = obj.get("type").cloned() {
 29→        if let Some(kind) = ty.as_str() {
 30→            obj.insert("type".to_string(), serde_json::json!([kind, "null"]));
 31→        } else if let Some(arr) = ty.as_array() {
 32→            let mut new_arr = arr.clone();
 33→            new_arr.push(serde_json::json!("null"));
 34→            obj.insert("type".to_string(), serde_json::Value::Array(new_arr));
 35→        }
 36→
 37→        // If the schema also constrains values with `enum`, add null there
 38→        // too. Without this the type says "nullable" but the enum doesn't
 39→        // include null, causing LLMs to send the literal string "null"
 40→        // instead of JSON null (issue #712).
 41→        add_null_to_enum(obj);
 42→        return;
 43→    }
 44→
