commit 4320903550682c1941d03f9fb55f36df9fed3823
Author: Cstewart-HC <100775598+Cstewart-HC@users.noreply.github.com>
Date:   Tue Apr 14 18:06:58 2026 -0300

    fix(providers): collapse type arrays in strict mode patching (#716)

    Gemini via OpenRouter rejects tool schemas with type arrays like
    type: [object, string] because Gemini cannot represent union
    types. OpenAI strict mode also requires type to be a single string.

    The cron tool (and others) use type arrays for fields like schedule
    and payload. When OpenRouter translates these to Gemini's
    function_declarations, the union type is lossy — properties may be
    dropped while required entries persist, causing INVALID_ARGUMENT.

    Fix by extending patch_schema_for_strict_mode to detect type arrays
    containing object (via new type_is_object helper) and collapse
    them to object. This triggers the existing strict mode path:
    additionalProperties: false, required rebuild from properties keys,
    and optional fields made nullable.

    The collapse is correct for tool calling because:
    - The object form is the intended structured shape
    - Bare strings/integers are convenience shorthand for non-tool contexts
    - OpenAI strict mode already prohibits type arrays

    Tests: 6 unit tests + 6 integration tests covering collapse behavior,
    nested schemas, non-object arrays (preserved), and end-to-end pipeline.

diff --git a/crates/providers/src/openai_compat/mod.rs b/crates/providers/src/openai_compat/mod.rs
index c4b2620e..9ddf5872 100644
--- a/crates/providers/src/openai_compat/mod.rs
+++ b/crates/providers/src/openai_compat/mod.rs
@@ -109,6 +109,22 @@ fn make_nullable(schema: &mut serde_json::Value) {
     }
 }

+/// Check whether a schema's `type` field designates an object.
+///
+/// Matches both `"type": "object"` and `"type": ["object", ...]`.
+/// Downstream providers like Gemini (via OpenRouter) cannot represent type
+/// arrays, and OpenAI's strict mode requires `type` to be a single string.
+fn type_is_object(obj: &serde_json::Map<String, serde_json::Value>) -> bool {
+    let Some(ty) = obj.get("type") else {
+        return false;
+    };
+    match ty {
+        serde_json::Value::String(s) => s == "object",
+        serde_json::Value::Array(arr) => arr.iter().any(|v| v.as_str() == Some("object")),
+        _ => false,
+    }
+}
+
 /// Recursively patch schema for OpenAI strict mode compliance.
 ///
 /// OpenAI's strict mode requires:
@@ -119,6 +135,14 @@ fn make_nullable(schema: &mut serde_json::Value) {
 /// model can send `null` for unused optional fields instead of fabricating
 /// placeholder values.
 ///
+/// Schemas with `type: ["object", "string", ...]` (union types) are collapsed
+/// to `type: "object"` because:
+/// - OpenAI strict mode requires `type` to be a single string
+/// - Gemini cannot represent type arrays at all
+/// - When `properties` is present, the object form is the intended shape for
+///   tool calling (bare strings/integers are convenience shorthand for non-tool
+///   contexts)
+///
 /// This function recursively patches nested objects in `properties`, array
 /// `items`, `anyOf`/`oneOf`/`allOf` variants, etc.
 pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
@@ -131,8 +155,14 @@ pub fn patch_schema_for_strict_mode(schema: &mut serde_json::Value) {
     // would prevent the recursive pass from recognising nested objects).
     let mut optional_props: Vec<String> = Vec::new();

-    // If this is an object type, apply strict mode requirements
-    if obj.get("type").and_then(|t| t.as_str()) == Some("object") {
+    // If this is an object type, apply strict mode requirements.
+    // Also handles union types like ["object", "string"] by collapsing to "object".
+    if type_is_object(obj) {
+        // Collapse type arrays (e.g. ["object", "string"]) to "object".
+        // OpenAI strict mode and Gemini both require a single string type.
+        if obj.get("type").and_then(|t| t.as_array()).is_some() {
+            obj.insert("type".to_string(), serde_json::json!("object"));
+        }
         // Add additionalProperties: false
         obj.insert("additionalProperties".to_string(), serde_json::json!(false));

